const input = $input.first().json;
const messages = input.messages;

if (!messages || messages.length === 0) {
  return [{ json: { ignore: true } }];
}

const message = messages[0];

let messageText = '';
if (message.type === 'interactive') {
  const interactive = message.interactive;
  if (interactive.type === 'button_reply') {
    messageText = interactive.button_reply.id;
  } else if (interactive.type === 'list_reply') {
    messageText = interactive.list_reply.id;
  }
} else if (message.type === 'text') {
  messageText = message.text?.body?.trim() || '';
}

// Detect language from first message text
let detectedLang = 'tr';
const lowerText = messageText.toLowerCase();
const langPatterns = {
  en: ['hello', 'hi', 'hey', 'good morning', 'good evening', 'how are you', 'start'],
  de: ['hallo', 'guten tag', 'guten morgen', 'guten abend', 'wie geht'],
  es: ['hola', 'buenos dias', 'buenas tardes', 'buenas noches', 'como estas'],
  cs: ['ahoj', 'dobry den', 'dobry', 'nazdar', 'cau', 'dobrý']
};
for (const [lang, patterns] of Object.entries(langPatterns)) {
  if (patterns.some(p => lowerText.includes(p))) {
    detectedLang = lang;
    break;
  }
}

return [{
  json: {
    phone: message.from,
    messageText,
    messageType: message.type,
    timestamp: message.timestamp,
    phoneNumberId: '967227463146831',
    detectedLang
  }
}];

