let state = 'new';
let userData = {};
let lang = detectedLang;

if (input.statusCode === 200 && input.data?.fields) {
  const fields = input.data.fields;
  state = fields.state?.stringValue || 'new';
  lang = fields.lang?.stringValue || detectedLang;
  userData = {
    firebase_uid: fields.firebase_uid?.stringValue || '',
    firebase_token: fields.firebase_token?.stringValue || '',
    refresh_token: fields.refresh_token?.stringValue || '',
    token_expires_at: fields.token_expires_at?.timestampValue || '',
    email: fields.email?.stringValue || '',
    business_id: fields.business_id?.stringValue || '',
    industry: fields.industry?.stringValue || '',
    business_name: fields.business_name?.stringValue || '',
    onboarding_step: fields.onboarding_step?.stringValue || '',
    current_tasks: [],
    answers: {},
    pending_task_id: fields.pending_task_id?.stringValue || '',
    pending_task_name: fields.pending_task_name?.stringValue || '',
    chat_history: []
  };
  if (fields.answers?.mapValue?.fields) {
    const ans = fields.answers.mapValue.fields;
    for (const [k, v] of Object.entries(ans)) {
      userData.answers[k] = parseInt(v.integerValue || v.stringValue || '5');
    }
  }
  if (fields.current_tasks?.arrayValue?.values) {
    userData.current_tasks = fields.current_tasks.arrayValue.values.map(v => {
      const f = v.mapValue?.fields || {};
      return {
        taskId: f.taskId?.stringValue || '',
        taskName: f.taskName?.stringValue || '',
        category: f.category?.stringValue || '',
        subCategory: f.subCategory?.stringValue || '',
        score: parseFloat(f.score?.doubleValue || f.score?.stringValue || '0'),
        impact_score: parseFloat(f.impact_score?.doubleValue || f.impact_score?.stringValue || '0'),
        why_text: f.why_text?.stringValue || '',
        how_steps: f.how_steps?.stringValue || '',
        template_text: f.template_text?.stringValue || '',
        time_estimate: f.time_estimate?.stringValue || ''
      };
    });
  }
  // Parse chat history
  if (fields.chat_history?.arrayValue?.values) {
    userData.chat_history = fields.chat_history.arrayValue.values.map(v => {
      const f = v.mapValue?.fields || {};
      return {
        role: f.role?.stringValue || '',
        content: f.content?.stringValue || ''
      };
    });
  }
}

return [{ json: { phone, messageText, phoneNumberId, state, lang, ...userData } }];

