// Gemini response parse + reply + save to chat history
const geminiResponse = $input.first().json;
const prevData = $('Handle Survey').first().json || $('Handle Idle').first().json || $('Handle Task Choice').first().json || {};
const phone = prevData.phone || $('Parse State').first().json.phone;
const phoneNumberId = prevData.phoneNumberId || $('Parse State').first().json.phoneNumberId;
const lang = prevData.lang || $('Translations').first().json.lang || 'tr';
const t = $('Translations').first().json.t;

let aiText = '';
try {
  aiText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {
  aiText = '';
}

const replyText = prevData.baseReply 
  ? prevData.baseReply + (aiText ? '\n\n' + t.aiAdvice + '\n' + aiText : '')
  : aiText || t.errorRetry;

// Add AI response to chat history (keep last 20)
let chatHistory = prevData.chat_history || [];
if (aiText) {
  chatHistory = [...chatHistory, { role: 'assistant', content: aiText }].slice(-20);
}

return [{
  json: {
    phone, phoneNumberId, lang,
    newState: prevData.newState || 'idle',
    replyType: prevData.replyType || 'text',
    replyText,
    replyBody: prevData.replyBody,
    replyButtons: prevData.replyButtons,
    firestoreAction: prevData.firestoreAction || 'none',
    firestoreFields: prevData.firestoreFields,
    chat_history: chatHistory
  }
}];

// Onboarding complete — prepare API call for first task recommendations
const data = $input.first().json;
const lang = data.lang || $('Translations').first().json.lang || 'tr';
const t = $('Translations').first().json.t;

if (data.onboardingComplete) {
  return [{
    json: {
      ...data,
      lang,
      fetchTasks: true,
      token: data.firebase_token || $('Parse State').first().json.firebase_token,
      baseReply: t.analysisComplete,
      newState: 'idle',
      replyType: 'text'
    }
  }];
}

return [$input.first()];

// STATE: idle
const phone = $json.phone;
const phoneNumberId = $json.phoneNumberId;
const t = $json.t;
const lang = $json.lang;
const input = $json.messageText.toLowerCase().trim();
const token = $json.firebase_token;
const industry = $json.industry;
const answers = $json.answers;
const businessName = $json.business_name;
const firebase_uid = $json.firebase_uid;
const business_id = $json.business_id;
const chatHistory = $json.chat_history || [];

// Task request
if (t.taskCommands.includes(input)) {
  return [{ json: { phone, phoneNumberId, lang, token, industry, answers, businessName, firebase_uid, business_id, fetchTasks: true, chat_history: chatHistory } }];
}

// Help
if (t.helpCommands.includes(input)) {
  return [{ json: { phone, phoneNumberId, lang, newState: 'idle', replyType: 'text', replyText: t.helpText, firestoreAction: 'none', chat_history: chatHistory } }];
}

// Build conversation context from last 10 messages
const recentHistory = chatHistory.slice(-10);
let historyContext = '';
if (recentHistory.length > 0) {
  historyContext = '\n\nPrevious conversation:\n' + recentHistory.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`).join('\n') + '\n\n';
}

// Add current message to history
const updatedHistory = [...chatHistory, { role: 'user', content: $json.messageText }].slice(-20);

// Free question — send to Gemini with conversation history
return [{
  json: {
    phone, phoneNumberId, lang,
    geminiSystemPrompt: t.geminiSystemPrompt,
    geminiPrompt: `User (${t.industryLabel(industry)} owner, business: "${businessName}").${historyContext}Current question: "${$json.messageText}". Give a short and practical answer from a business growth perspective in ${t.geminiLang}. If related to tasks, suggest typing "${t.taskCommands[0]}".`,
    newState: 'idle',
    replyType: 'text',
    baseReply: '',
    firestoreAction: 'none',
    useGemini: true,
    chat_history: updatedHistory
  }
}];

// Check task_history in Firestore for blacklisted/recently completed tasks
const recs = $input.first().json.recommendations || [];
const firebase_uid = $('Handle Idle').first().json.firebase_uid || '';
const business_id = $('Handle Idle').first().json.business_id || '';
const phone = $('Parse State').first().json.phone;
const phoneNumberId = $('Parse State').first().json.phoneNumberId;
const lang = $('Translations').first().json.lang || 'tr';
const t = $('Translations').first().json.t;
const token = $('Handle Idle').first().json.token;
const industry = $('Handle Idle').first().json.industry;
const businessName = $('Handle Idle').first().json.businessName;
const answers = $('Handle Idle').first().json.answers;

// Pass data forward for task history lookup
return [{
  json: {
    phone, phoneNumberId, lang, token, industry, businessName, answers,
    firebase_uid, business_id,
    recommendations: recs,
    historyDocId: firebase_uid && business_id ? `${firebase_uid}_${business_id}` : ''
  }
}];

// Filter recommendations against task_history (blacklisted + recently completed)
const historyResponse = $input.first().json;
const prevData = $('Check Task History Prepare').first().json;
const recs = prevData.recommendations || [];

let excludedIds = new Set();
let blockedArray = [];

if (historyResponse.statusCode === 200 && historyResponse.data?.fields) {
  const fields = historyResponse.data.fields;

  // Get blocked array
  if (fields.blocked?.arrayValue?.values) {
    blockedArray = fields.blocked.arrayValue.values.map(v => v.stringValue || v.integerValue || '');
    blockedArray.forEach(id => excludedIds.add(String(id)));
  }

  // Get tasks map — check for recently completed (within 3 days)
  if (fields.tasks?.mapValue?.fields) {
    const tasksMap = fields.tasks.mapValue.fields;
    const threeDaysAgo = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000);
    for (const [taskKey, taskVal] of Object.entries(tasksMap)) {
      const tf = taskVal.mapValue?.fields || {};
      const statusType = parseInt(tf.status_type?.integerValue || '-1');
      const lastAt = tf.last_at?.timestampValue ? new Date(tf.last_at.timestampValue) : null;
      // status_type 0 = completed, check cooldown
      if (statusType === 0 && lastAt && lastAt > threeDaysAgo) {
        const tid = tf.task_id?.integerValue || tf.task_id?.stringValue || taskKey;
        excludedIds.add(String(tid));
      }
    }
  }
}

// Filter recommendations: extract numeric ID from taskId like "cafe_124" -> "124"
const filteredRecs = recs.filter(r => {
  const numericId = String(r.taskId).replace(/^[a-z]+_/i, '');
  return !excludedIds.has(numericId) && !excludedIds.has(String(r.taskId));
});

const top3 = filteredRecs.slice(0, 3);

return [{
  json: {
    ...prevData,
    recommendations: top3,
    excludedIds: Array.from(excludedIds)
  }
}];

// Fetch full task details from Firestore for the top 3 recommendations
const prevData = $input.first().json;
const top3 = prevData.recommendations || [];

if (top3.length === 0) {
  return [{ json: { ...prevData, enrichedTasks: [] } }];
}

// Build batch query bodies for each task
const queries = top3.map(r => {
  // Extract numeric task_id from "cafe_124" -> 124
  const numericId = parseInt(String(r.taskId).replace(/^[a-z]+_/i, ''));
  return {
    taskId: r.taskId,
    taskName: r.taskName,
    category: r.category,
    subCategory: r.subCategory,
    score: r.score,
    numericId
  };
});

return [{ json: { ...prevData, taskQueries: queries } }];

