// Merge Firestore task details with API recommendations
const firestoreResults = $input.all().map(item => item.json);
const prevData = $('Prepare Task Queries').first().json;
const taskQueries = prevData.taskQueries || [];
const lang = prevData.lang || 'tr';
const phone = prevData.phone;
const phoneNumberId = prevData.phoneNumberId;
const t = $('Translations').first().json.t;
const businessName = prevData.businessName || '';
const industry = prevData.industry || '';

// Helper: extract localized text from Firestore field
// Field can be a plain string or a map like {tr: '...', en: '...'}
function getLocalized(fieldVal, lang) {
  if (!fieldVal) return '';
  if (fieldVal.stringValue) return fieldVal.stringValue;
  if (fieldVal.mapValue?.fields) {
    const locField = fieldVal.mapValue.fields[lang];
    if (locField?.stringValue) return locField.stringValue;
    // Fallback to tr, then en, then first available
    if (fieldVal.mapValue.fields.tr?.stringValue) return fieldVal.mapValue.fields.tr.stringValue;
    if (fieldVal.mapValue.fields.en?.stringValue) return fieldVal.mapValue.fields.en.stringValue;
    const keys = Object.keys(fieldVal.mapValue.fields);
    if (keys.length > 0) return fieldVal.mapValue.fields[keys[0]]?.stringValue || '';
  }
  return '';
}

// Parse Firestore task docs into a map by task_id
const taskDetailsMap = {};
for (const result of firestoreResults) {
  const docs = Array.isArray(result) ? result : [result];
  for (const doc of docs) {
    if (!doc.document) continue;
    const fields = doc.document.fields || {};
    const taskId = parseInt(fields.task_id?.integerValue || '0');
    if (taskId) {
      taskDetailsMap[taskId] = {
        why_text: getLocalized(fields.why_text, lang),
        how_steps: getLocalized(fields.how_steps, lang),
        template_text: getLocalized(fields.template_text, lang),
        time_estimate: getLocalized(fields.time_estimate, lang),
        impact_score: parseFloat(fields.impact_score?.doubleValue || fields.impact_score?.integerValue || '0')
      };
    }
  }
}

// Enrich task queries with Firestore details
const enrichedTasks = taskQueries.map(q => {
  const details = taskDetailsMap[q.numericId] || {};
  return {
    taskId: q.taskId,
    taskName: q.taskName,
    category: q.category,
    subCategory: q.subCategory,
    score: q.score,
    numericId: q.numericId,
    why_text: details.why_text || '',
    how_steps: details.how_steps || '',
    template_text: details.template_text || '',
    time_estimate: details.time_estimate || '',
    impact_score: details.impact_score || q.score || 0
  };
});

if (enrichedTasks.length === 0) {
  return [{ json: { phone, phoneNumberId, lang, newState: 'idle', replyType: 'text', replyText: t.noTasks, firestoreAction: 'none' } }];
}

let msg = t.todaysTasks;
enrichedTasks.forEach((r, i) => {
  const emoji = ['1\uFE0F\u20E3', '2\uFE0F\u20E3', '3\uFE0F\u20E3'][i];
  const impact = r.score >= 80 ? '\u{1F525} ' + t.impactHigh : r.score >= 50 ? '\u26A1 ' + t.impactMedium : '\u{1F4A1} ' + t.impactLow;
  msg += `${emoji} *${r.taskName}*\n   \u{1F4C1} ${r.category} > ${r.subCategory}\n   ${impact} (${r.score.toFixed(1)})`;
  if (r.time_estimate) msg += `\n   \u23F1 ${r.time_estimate}`;
  msg += '\n\n';
});
msg += t.taskDetailPrompt;

const taskNames = enrichedTasks.map(r => r.taskName).join(', ');

return [{ json: {
  phone, phoneNumberId, lang,
  newState: 'awaiting_task_choice',
  replyType: 'text',
  baseReply: msg,
  geminiSystemPrompt: t.geminiSystemPrompt,
  geminiPrompt: `${t.industryLabel(industry)} owner "${businessName}" has been suggested 3 tasks today: ${taskNames}. Write a 1-2 sentence motivational message. Highlight the importance of the tasks. Respond in ${t.geminiLang}.`,
  firestoreAction: 'update',
  firestoreFields: { current_tasks: enrichedTasks.map(r => ({ taskId: r.taskId, taskName: r.taskName, category: r.category, subCategory: r.subCategory, score: r.score, impact_score: r.impact_score, why_text: r.why_text, how_steps: r.how_steps, template_text: r.template_text, time_estimate: r.time_estimate })) }
} }];

// STATE: awaiting_task_choice
const phone = $json.phone;
const phoneNumberId = $json.phoneNumberId;
const t = $json.t;
const lang = $json.lang;
const input = $json.messageText.trim();
const tasks = $json.current_tasks || [];
const choice = parseInt(input);
if (isNaN(choice) || choice < 1 || choice > tasks.length) {
  return [{ json: { phone, phoneNumberId, lang, newState: 'awaiting_task_choice', replyType: 'text', replyText: t.enterNumber, firestoreAction: 'none' } }];
}
const task = tasks[choice - 1];

// Build detail message from Firestore data
let detailMsg = `\u{1F4CC} *${task.taskName}*\n${task.category} > ${task.subCategory}`;

if (task.why_text) {
  detailMsg += `\n\n\u{1F4A1} *${t.whyLabel || 'Why'}:*\n${task.why_text}`;
}
if (task.how_steps) {
  detailMsg += `\n\n\u{1F4DD} *${t.howLabel || 'How'}:*\n${task.how_steps}`;
}
if (task.template_text) {
  detailMsg += `\n\n\u{1F4C4} *${t.templateLabel || 'Template'}:*\n${task.template_text}`;
}
if (task.time_estimate) {
  detailMsg += `\n\n\u23F1 *${t.timeLabel || 'Time'}:* ${task.time_estimate}`;
}

// If we have Firestore details, no need for Gemini to generate them
const hasDetails = !!(task.why_text || task.how_steps);

return [{
  json: {
    phone, phoneNumberId, lang,
    selectedTask: task,
    newState: 'awaiting_action',
    replyType: 'interactive_buttons',
    replyButtons: [
      { id: 'done', title: t.done },
      { id: 'snooze', title: t.snooze },
      { id: 'dismiss', title: t.dismiss }
    ],
    geminiSystemPrompt: hasDetails ? null : t.geminiSystemPrompt,
    geminiPrompt: hasDetails ? null : `Explain the task "${task.taskName}" briefly. Category: ${task.category} > ${task.subCategory}. Why is it important, how to do it, in 3-4 sentences. Write from a ${t.industryLabel($json.industry)} perspective. Respond in ${t.geminiLang}.`,
    baseReply: detailMsg,
    replyBody: detailMsg,
    firestoreAction: 'update',
    firestoreFields: { pending_task_id: task.taskId, pending_task_name: task.taskName }
  }
}];

// STATE: awaiting_action
const phone = $json.phone;
