// Parse Firestore query results into user list
const results = $input.all().map(item => item.json);
const users = [];

for (const result of results) {
  const docs = Array.isArray(result) ? result : [result];
  for (const doc of docs) {
    if (!doc.document) continue;
    const fields = doc.document.fields || {};
    const phone = doc.document.name.split('/').pop();

    const answers = {};
    if (fields.answers?.mapValue?.fields) {
      for (const [k, v] of Object.entries(fields.answers.mapValue.fields)) {
        answers[k] = parseInt(v.integerValue || v.stringValue || '5');
      }
    }

    if (Object.keys(answers).length < 7) continue;

    users.push({
      phone,
      firebase_token: fields.firebase_token?.stringValue || '',
      refresh_token: fields.refresh_token?.stringValue || '',
      token_expires_at: fields.token_expires_at?.timestampValue || '',
      industry: fields.industry?.stringValue || 'rest',
      answers,
      phoneNumberId: fields.phone_number_id?.stringValue || '',
      lang: fields.lang?.stringValue || 'tr',
      firebase_uid: fields.firebase_uid?.stringValue || '',
      business_id: fields.business_id?.stringValue || ''
    });
  }
}

return users.map(u => ({ json: u }));

// Check if token needs refresh
