const user = $('[Daily] Check Token Expiry').first().json;
const firebase_uid = user.firebase_uid || '';
const business_id = user.business_id || '';
const historyDocId = firebase_uid && business_id ? `${firebase_uid}_${business_id}` : '';

return [{
  json: {
    recommendations: recs,
    phone: user.phone,
    phoneNumberId: user.phoneNumberId,
    lang: user.lang || 'tr',
    firebase_uid,
    business_id,
    industry: user.industry,
    firebase_token: user.firebase_token,
    historyDocId
  }
}];

// Filter recommendations against task_history for daily flow
const historyResponse = $input.first().json;
const prevData = $('[Daily] Check History Prepare').first().json;
const recs = prevData.recommendations || [];

let excludedIds = new Set();

if (historyResponse.statusCode === 200 && historyResponse.data?.fields) {
  const fields = historyResponse.data.fields;
  if (fields.blocked?.arrayValue?.values) {
    fields.blocked.arrayValue.values.forEach(v => excludedIds.add(String(v.stringValue || v.integerValue || '')));
  }
  if (fields.tasks?.mapValue?.fields) {
    const tasksMap = fields.tasks.mapValue.fields;
    const threeDaysAgo = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000);
    for (const [taskKey, taskVal] of Object.entries(tasksMap)) {
      const tf = taskVal.mapValue?.fields || {};
      const statusType = parseInt(tf.status_type?.integerValue || '-1');
      const lastAt = tf.last_at?.timestampValue ? new Date(tf.last_at.timestampValue) : null;
      if (statusType === 0 && lastAt && lastAt > threeDaysAgo) {
        const tid = tf.task_id?.integerValue || tf.task_id?.stringValue || taskKey;
        excludedIds.add(String(tid));
      }
    }
  }
}

const filteredRecs = recs.filter(r => {
  const numericId = String(r.taskId).replace(/^[a-z]+_/i, '');
  return !excludedIds.has(numericId) && !excludedIds.has(String(r.taskId));
});

const top3 = filteredRecs.slice(0, 3);

return [{
  json: {
    ...prevData,
    recommendations: top3
  }
}];

// Prepare task queries for Firestore fetch in daily flow
const prevData = $input.first().json;
const top3 = prevData.recommendations || [];

if (top3.length === 0) return [];

const queries = top3.map(r => {
  const numericId = parseInt(String(r.taskId).replace(/^[a-z]+_/i, ''));
  return {
    taskId: r.taskId,
    taskName: r.taskName,
    category: r.category,
    subCategory: r.subCategory,
    score: r.score,
    numericId
  };
});

return [{ json: { ...prevData, taskQueries: queries } }];

