// Format daily message with full Firestore task details
const firestoreResults = $input.all().map(item => item.json);
const prevData = $('[Daily] Prepare Task Queries').first().json;
const taskQueries = prevData.taskQueries || [];
const lang = prevData.lang || 'tr';
const user = $('[Daily] Check Token Expiry').first().json;

if (taskQueries.length === 0) return [];

// Helper: extract localized text from Firestore field
function getLocalized(fieldVal, lang) {
  if (!fieldVal) return '';
  if (fieldVal.stringValue) return fieldVal.stringValue;
  if (fieldVal.mapValue?.fields) {
    const locField = fieldVal.mapValue.fields[lang];
    if (locField?.stringValue) return locField.stringValue;
    if (fieldVal.mapValue.fields.tr?.stringValue) return fieldVal.mapValue.fields.tr.stringValue;
    if (fieldVal.mapValue.fields.en?.stringValue) return fieldVal.mapValue.fields.en.stringValue;
    const keys = Object.keys(fieldVal.mapValue.fields);
    if (keys.length > 0) return fieldVal.mapValue.fields[keys[0]]?.stringValue || '';
  }
  return '';
}

// Parse Firestore task docs into a map by task_id
const taskDetailsMap = {};
for (const result of firestoreResults) {
  const docs = Array.isArray(result) ? result : [result];
  for (const doc of docs) {
    if (!doc.document) continue;
    const fields = doc.document.fields || {};
    const taskId = parseInt(fields.task_id?.integerValue || '0');
    if (taskId) {
      taskDetailsMap[taskId] = {
        why_text: getLocalized(fields.why_text, lang),
        how_steps: getLocalized(fields.how_steps, lang),
        template_text: getLocalized(fields.template_text, lang),
        time_estimate: getLocalized(fields.time_estimate, lang),
        impact_score: parseFloat(fields.impact_score?.doubleValue || fields.impact_score?.integerValue || '0')
      };
    }
  }
}

// Enrich tasks
const enrichedTasks = taskQueries.map(q => {
  const details = taskDetailsMap[q.numericId] || {};
  return {
    taskId: q.taskId,
    taskName: q.taskName,
    category: q.category,
    subCategory: q.subCategory,
    score: q.score,
    numericId: q.numericId,
    why_text: details.why_text || '',
    how_steps: details.how_steps || '',
    template_text: details.template_text || '',
    time_estimate: details.time_estimate || '',
    impact_score: details.impact_score || q.score || 0
  };
});

// Inline translations for daily message
const dailyT = {
  tr: { goodMorning: 'Gunaydin! Bugunun gorevleri:\n\n', high: 'Yuksek', medium: 'Orta', low: 'Dusuk', impact: 'Etki', detailPrompt: 'Detay icin numara girin (1, 2, 3):' },
  en: { goodMorning: 'Good morning! Today\'s tasks:\n\n', high: 'High', medium: 'Medium', low: 'Low', impact: 'Impact', detailPrompt: 'Enter a number for details (1, 2, 3):' },
  de: { goodMorning: 'Guten Morgen! Heutige Aufgaben:\n\n', high: 'Hoch', medium: 'Mittel', low: 'Niedrig', impact: 'Auswirkung', detailPrompt: 'Geben Sie eine Nummer fuer Details ein (1, 2, 3):' },
  es: { goodMorning: 'Buenos dias! Tareas de hoy:\n\n', high: 'Alto', medium: 'Medio', low: 'Bajo', impact: 'Impacto', detailPrompt: 'Ingresa un numero para detalles (1, 2, 3):' },
  cs: { goodMorning: 'Dobre rano! Dnesni ukoly:\n\n', high: 'Vysoky', medium: 'Stredni', low: 'Nizky', impact: 'Dopad', detailPrompt: 'Zadejte cislo pro podrobnosti (1, 2, 3):' }
};
const dt = dailyT[lang] || dailyT.tr;

let msg = dt.goodMorning;
enrichedTasks.forEach((r, i) => {
  const impact = r.score >= 80 ? dt.high : r.score >= 50 ? dt.medium : dt.low;
  msg += `*${i + 1}.* ${r.taskName}\n   ${r.category} > ${r.subCategory}\n   ${dt.impact}: ${impact}`;
  if (r.time_estimate) msg += `\n   \u23F1 ${r.time_estimate}`;
  msg += '\n\n';
});
msg += dt.detailPrompt;

return [{
  json: {
    phone: prevData.phone,
    phoneNumberId: prevData.phoneNumberId,
    lang,
    message: msg,
    current_tasks: enrichedTasks.map(r => ({
      taskId: r.taskId,
      taskName: r.taskName,
      category: r.category,
      subCategory: r.subCategory,
      score: r.score,
      impact_score: r.impact_score,
      why_text: r.why_text,
      how_steps: r.how_steps,
      template_text: r.template_text,
      time_estimate: r.time_estimate
    }))
  }
}];

// Filter users whose token expires within 15 minutes
const results = $input.all().map(item => item.json);
const users = [];
const threshold = new Date(Date.now() + 15 * 60 * 1000);

for (const result of results) {
  const docs = Array.isArray(result) ? result : [result];
  for (const doc of docs) {
    if (!doc.document) continue;
    const fields = doc.document.fields || {};
    const phone = doc.document.name.split('/').pop();
    const tokenExpires = fields.token_expires_at?.timestampValue;
    const refreshToken = fields.refresh_token?.stringValue;

    if (!refreshToken) continue;

    const expiresDate = tokenExpires ? new Date(tokenExpires) : new Date(0);
    if (expiresDate <= threshold) {
      users.push({
        phone,
        refresh_token: refreshToken,
        firebase_uid: fields.firebase_uid?.stringValue || ''
      });
    }
  }
}

if (users.length === 0) {
  return [{ json: { noUsersToRefresh: true } }];
}

return users.map(u => ({ json: u }));
